    'type': 'object',
    'required': ['actionGroup', 'result'],
    'properties': {
        'actionGroup': {'type': 'string'},
        'result': {'type': 'object', 'additionalProperties': True}
    }
}

def lambda_handler(event, context):
    try:
        # Your business logic here
        result = process_business_logic(event)

        response = {
            'actionGroup': event['actionGroup'],
            'result': {
                'status': 'success',
                'data': result
            }
        }

        validator = Draft7Validator(LAMBDA_SCHEMA)
        validator.validate(response)

        return {
            'statusCode': 200,
            'body': json.dumps(response),
            'headers': {'Content-Type': 'application/json'}
        }
    except Exception as e:
        return {
            'statusCode': 400,
            'body': json.dumps({
                'actionGroup': event.get('actionGroup'),
                'result': {'status': 'error', 'message': str(e)}
            })
        }

import boto3

bedrock_agent = boto3.client('bedrock-agent-runtime')

def invoke_agent_with_kb_verification(agent_id, alias_id, session_id, input_text):
    response = bedrock_agent.invoke_agent(
        agentId=agent_id,
        agentAliasId=alias_id,
        sessionId=session_id,
        inputText=input_text,
        enableTrace=True  # Critical for KB retrieval debugging
    )

    # Verify retrieved documents contain relevant content
    trace = response.get('trace', {})
    if 'orchestrationTrace' in trace:
        kb_steps = [step for step in trace['orchestrationTrace'] 
                   if step.get('type') == 'knowledgeBase']

        for kb_step in kb_steps:
            documents = kb_step.get('retrievedDocuments', [])
            if not documents:
                # Force re-retrieval with different parameters
                response = bedrock_agent.invoke_agent(
                    agentId=agent_id,
                    agentAliasId=alias_id,
                    sessionId=session_id,
                    inputText=f"[RETRIEVE]: {input_text}",
                    sessionState={
                        'knowledgeBaseConfiguration': {
                            'knowledgeBaseId': 'YOUR_KB_ID',
                            'retrievalConfiguration': {
                                'vectorSearchConfiguration': {
                                    'numberOfResults': 10,
                                    'overrideSearchType': 'HYBRID'
                                }
                            }
                        }
                    }
                )
    return response

